using System;
using System.Collections.Generic;
using System.IO;
using System.Xml;

public class XmlConfigurationParser
{
    /// <summary>
    /// Parses an XML configuration file from an untrusted source (enterprise customer upload)
    /// and extracts settings into a Dictionary. External entities and DTD processing are disabled
    /// to prevent XXE (XML External Entity) attacks.
    /// </summary>
    /// <param name="xmlContent">The raw XML content as a string.</param>
    /// <returns>A dictionary of configuration key-value pairs.</returns>
    public static Dictionary<string, string> ParseConfiguration(string xmlContent)
    {
        if (string.IsNullOrWhiteSpace(xmlContent))
        {
            throw new ArgumentException("XML content cannot be null or empty.", nameof(xmlContent));
        }

        var settings = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);

        // Configure XmlReaderSettings to prevent XXE and related attacks
        XmlReaderSettings readerSettings = new XmlReaderSettings
        {
            // Disable DTD processing entirely to prevent XXE attacks
            DtdProcessing = DtdProcessing.Prohibit,

            // Do not resolve any external resources (DTDs, entities, schemas, etc.)
            XmlResolver = null,

            // Limit the maximum number of characters to prevent denial-of-service via large payloads
            MaxCharactersInDocument = 10_000_000, // 10 million characters max
            MaxCharactersFromEntities = 0,        // No characters from entity expansion

            // Ignore comments and processing instructions from untrusted input
            IgnoreComments = true,
            IgnoreProcessingInstructions = true,
        };

        using (StringReader stringReader = new StringReader(xmlContent))
        using (XmlReader reader = XmlReader.Create(stringReader, readerSettings))
        {
            XmlDocument xmlDoc = new XmlDocument
            {
                // Also disable the XmlResolver on the XmlDocument itself
                XmlResolver = null
            };

            xmlDoc.Load(reader);

            // Extract settings from the XML document
            // Supports multiple common configuration XML formats:
            //
            // Format 1: <configuration><settings><setting key="..." value="..." /></settings></configuration>
            // Format 2: <configuration><appSettings><add key="..." value="..." /></appSettings></configuration>
            // Format 3: <configuration><setting name="...">value</setting></configuration>
            // Format 4: <config><key1>value1</key1><key2>value2</key2></config>

            XmlElement root = xmlDoc.DocumentElement;
            if (root == null)
            {
                throw new XmlException("XML document has no root element.");
            }

            // Try to find <setting> or <add> elements with key/value attributes
            ExtractKeyValueElements(root, settings);

            // If no key-value elements were found, try treating child elements as key-value pairs
            if (settings.Count == 0)
            {
                ExtractElementBasedSettings(root, settings);
            }
        }

        return settings;
    }

    /// <summary>
    /// Parses an XML configuration file from a stream.
    /// </summary>
    /// <param name="xmlStream">The stream containing XML content.</param>
    /// <returns>A dictionary of configuration key-value pairs.</returns>
    public static Dictionary<string, string> ParseConfiguration(Stream xmlStream)
    {
        if (xmlStream == null)
        {
            throw new ArgumentNullException(nameof(xmlStream));
        }

        using (StreamReader streamReader = new StreamReader(xmlStream))
        {
            string xmlContent = streamReader.ReadToEnd();
            return ParseConfiguration(xmlContent);
        }
    }

    /// <summary>
    /// Recursively searches for elements with key/value or name/value attribute patterns
    /// commonly used in configuration files (e.g., <add key="..." value="..." />).
    /// </summary>
    private static void ExtractKeyValueElements(XmlNode node, Dictionary<string, string> settings)
    {
        if (node == null) return;

        if (node is XmlElement element)
        {
            string key = null;
            string value = null;

            // Check for key="..." value="..." pattern
            if (element.HasAttribute("key") && element.HasAttribute("value"))
            {
                key = element.GetAttribute("key");
                value = element.GetAttribute("value");
            }
            // Check for name="..." value="..." pattern
            else if (element.HasAttribute("name") && element.HasAttribute("value"))
            {
                key = element.GetAttribute("name");
                value = element.GetAttribute("value");
            }
            // Check for key="..." with inner text as value
            else if (element.HasAttribute("key") && !element.HasChildNodes)
            {
                key = element.GetAttribute("key");
                value = element.InnerText?.Trim() ?? string.Empty;
            }
            // Check for name="..." with inner text as value
            else if (element.HasAttribute("name") && element.ChildNodes.Count <= 1)
            {
                key = element.GetAttribute("name");
                value = element.InnerText?.Trim() ?? string.Empty;
            }

            if (!string.IsNullOrEmpty(key))
            {
                settings[key] = value ?? string.Empty;
            }
        }

        // Recurse into child nodes
        foreach (XmlNode child in node.ChildNodes)
        {
            if (child is XmlElement)
            {
                ExtractKeyValueElements(child, settings);
            }
        }
    }

    /// <summary>
    /// Extracts settings from leaf elements where the element name is the key
    /// and the inner text is the value (e.g., <DatabaseHost>localhost</DatabaseHost>).
    /// </summary>
    private static void ExtractElementBasedSettings(XmlNode node, Dictionary<string, string> settings)
    {
        if (node == null) return;

        foreach (XmlNode child in node.ChildNodes)
        {
            if (child is XmlElement element)
            {
                // If this element has no child elements (it's a leaf), treat it as a setting
                bool hasChildElements = false;
                foreach (XmlNode grandChild in element.ChildNodes)
                {
                    if (grandChild is XmlElement)
                    {
                        hasChildElements = true;
                        break;
                    }
                }

                if (!hasChildElements)
                {
                    string key = element.LocalName;
                    string value = element.InnerText?.Trim() ?? string.Empty;
                    settings[key] = value;
                }
                else
                {
                    // Recurse into container elements
                    ExtractElementBasedSettings(element, settings);
                }
            }
        }
    }
